export component ScannerTab inherits Rectangle {
    VerticalLayout {
        padding: 24px;
        spacing: 16px;
        alignment: center;

        Text {
            text: "Scanner";
            font-size: 18px;
            font-weight: 600;
            horizontal-alignment: center;
        }

        Text {
            text: "Scanner behavior is reserved for a later port phase.";
            font-size: 14px;
            horizontal-alignment: center;
        }
    }
}

import { TabWidget } from "std-widgets.slint";
import { OverviewTab, OverviewUiRow } from "overview_tab.slint";
import { F4seTab, F4seUiRow } from "f4se_tab.slint";
import { ScannerTab } from "scanner_tab.slint";
import { ToolsTab } from "tools_tab.slint";
import { SettingsTab } from "settings_tab.slint";
import { AboutTab } from "about_tab.slint";

export component MainWindow inherits Window {
    in-out property <string> update-source: "nexus";
    in-out property <string> log-level: "info";
    in-out property <string> overview-refresh-message: "Overview has not been refreshed.";
    in-out property <bool> overview-refresh-busy: false;
    in-out property <[OverviewUiRow]> overview-top-rows;
    in-out property <[OverviewUiRow]> overview-binary-rows;
    in-out property <[OverviewUiRow]> overview-archive-rows;
    in-out property <[OverviewUiRow]> overview-module-rows;
    in-out property <string> overview-problems-summary: "Problems: 0";
    in-out property <[OverviewUiRow]> overview-problem-rows;
    in-out property <string> overview-update-heading: "";
    in-out property <string> overview-nexus-update-label: "Nexus Mods";
    in-out property <bool> overview-nexus-update-enabled: false;
    in-out property <string> overview-github-update-label: "GitHub";
    in-out property <bool> overview-github-update-enabled: false;
    in-out property <bool> overview-game-path-enabled: false;
    in-out property <string> overview-downgrade-label: "Downgrade Manager...";
    in-out property <bool> overview-downgrade-enabled: false;
    in-out property <string> overview-downgrade-status: "Deferred until the Downgrade Manager workflow is ported.";
    in-out property <string> overview-archive-patcher-label: "Archive Patcher...";
    in-out property <bool> overview-archive-patcher-enabled: false;
    in-out property <string> overview-archive-patcher-status: "Deferred until the Archive Patcher workflow is ported.";
    in-out property <string> overview-last-action-error: "";
    in-out property <string> f4se-status-text: "F4SE scan has not run yet.";
    in-out property <bool> f4se-busy: false;
    in-out property <string> f4se-loading-or-error-text: "";
    in-out property <string> f4se-unknown-game-detail: "";
    in-out property <[F4seUiRow]> f4se-rows;
    property <int> active-tab-index: 0;
    property <bool> f4se-tab-activation-observed: false;
    in-out property <string> tools-last-action-error: "";
    in-out property <string> tools-disabled-utility-status: "Downgrade Manager is deferred until S09; Archive Patcher is deferred until S10.";
    in-out property <string> about-last-action-error: "";
    in-out property <string> about-nexus-copy-label: "Copy Link";
    in-out property <bool> about-nexus-copy-enabled: true;
    in-out property <string> about-discord-copy-label: "Copy Invite";
    in-out property <bool> about-discord-copy-enabled: true;
    in-out property <string> about-github-copy-label: "Copy Link";
    in-out property <bool> about-github-copy-enabled: true;
    callback update-source-selected(string);
    callback log-level-selected(string);
    callback overview-refresh-requested();
    callback overview-open-game-path-requested();
    callback overview-open-nexus-update-requested();
    callback overview-open-github-update-requested();
    callback overview-open-downgrade-manager-requested();
    callback overview-open-archive-patcher-requested();
    callback f4se-tab-activated();
    callback tool-action-requested(string);
    callback about-open-requested(string);
    callback about-copy-requested(string);
    callback about-copy-label-reset-requested(string);

    title: "Collective Modding Toolkit";
    width: 900px;
    height: 640px;

    // The tab labels and order mirror CMT/src/cm_checker.py and CMT/src/enums.py.
    f4se-tab-lazy-activation := Timer {
        interval: 16ms;
        running: root.active-tab-index == 1 && !root.f4se-tab-activation-observed;
        triggered => {
            root.f4se-tab-activation-observed = true;
            root.f4se-tab-activated();
        }
    }

    TabWidget {
        current-index <=> root.active-tab-index;
        Tab {
            title: "Overview";
            OverviewTab {
                overview-refresh-message <=> root.overview-refresh-message;
                overview-refresh-busy <=> root.overview-refresh-busy;
                overview-top-rows <=> root.overview-top-rows;
                overview-binary-rows <=> root.overview-binary-rows;
                overview-archive-rows <=> root.overview-archive-rows;
                overview-module-rows <=> root.overview-module-rows;
                overview-problems-summary <=> root.overview-problems-summary;
                overview-problem-rows <=> root.overview-problem-rows;
                overview-update-heading <=> root.overview-update-heading;
                overview-nexus-update-label <=> root.overview-nexus-update-label;
                overview-nexus-update-enabled <=> root.overview-nexus-update-enabled;
                overview-github-update-label <=> root.overview-github-update-label;
                overview-github-update-enabled <=> root.overview-github-update-enabled;
                overview-game-path-enabled <=> root.overview-game-path-enabled;
                overview-downgrade-label <=> root.overview-downgrade-label;
                overview-downgrade-enabled <=> root.overview-downgrade-enabled;
                overview-downgrade-status <=> root.overview-downgrade-status;
                overview-archive-patcher-label <=> root.overview-archive-patcher-label;
                overview-archive-patcher-enabled <=> root.overview-archive-patcher-enabled;
                overview-archive-patcher-status <=> root.overview-archive-patcher-status;
                overview-last-action-error <=> root.overview-last-action-error;
                refresh-requested => {
                    root.overview-refresh-requested();
                }
                open-game-path-requested => {
                    root.overview-open-game-path-requested();
                }
                open-nexus-update-requested => {
                    root.overview-open-nexus-update-requested();
                }
                open-github-update-requested => {
                    root.overview-open-github-update-requested();
                }
                open-downgrade-manager-requested => {
                    root.overview-open-downgrade-manager-requested();
                }
                open-archive-patcher-requested => {
                    root.overview-open-archive-patcher-requested();
                }
            }
        }

        Tab {
            title: "F4SE";
            F4seTab {
                f4se-status-text <=> root.f4se-status-text;
                f4se-busy <=> root.f4se-busy;
                f4se-loading-or-error-text <=> root.f4se-loading-or-error-text;
                f4se-unknown-game-detail <=> root.f4se-unknown-game-detail;
                f4se-rows <=> root.f4se-rows;
            }
        }

        Tab {
            title: "Scanner";
            ScannerTab {}
        }

        Tab {
            title: "Tools";
            ToolsTab {
                tools-last-action-error <=> root.tools-last-action-error;
                tools-disabled-utility-status <=> root.tools-disabled-utility-status;
                tool-action-requested(action_id) => {
                    root.tool-action-requested(action_id);
                }
            }
        }

        Tab {
            title: "Settings";
            SettingsTab {
                update-source <=> root.update-source;
                log-level <=> root.log-level;
                update-source-selected(value) => {
                    root.update-source-selected(value);
                }
                log-level-selected(value) => {
                    root.log-level-selected(value);
                }
            }
        }

        Tab {
            title: "About";
            AboutTab {
                about-last-action-error <=> root.about-last-action-error;
                about-nexus-copy-label <=> root.about-nexus-copy-label;
                about-nexus-copy-enabled <=> root.about-nexus-copy-enabled;
                about-discord-copy-label <=> root.about-discord-copy-label;
                about-discord-copy-enabled <=> root.about-discord-copy-enabled;
                about-github-copy-label <=> root.about-github-copy-label;
                about-github-copy-enabled <=> root.about-github-copy-enabled;
                about-open-requested(action_id) => {
                    root.about-open-requested(action_id);
                }
                about-copy-requested(action_id) => {
                    root.about-copy-requested(action_id);
                }
                about-copy-label-reset-requested(action_id) => {
                    root.about-copy-label-reset-requested(action_id);
                }
            }
        }
    }
}

import { GroupBox, ScrollView } from "std-widgets.slint";

export struct F4seUiRow {
    dll: string,
    og: string,
    ng: string,
    ae: string,
    your_game: string,
    severity: string,
    detail: string,
}

component SeverityCell inherits Text {
    in property <string> severity: "neutral";
    in property <bool> important: false;

    color: root.severity == "compatible" ? #8fdc8f :
        root.severity == "warning" ? #ffd166 :
        root.severity == "incompatible" ? #ff7b7b :
        #d8d8d8;
    font-weight: root.important ? 600 : 400;
    vertical-alignment: center;
}

component F4seHeaderCell inherits Text {
    in property <length> cell-width: 72px;

    width: root.cell-width;
    color: #f3f3f3;
    font-size: 12px;
    font-weight: 700;
    horizontal-alignment: center;
}

component F4seRow inherits Rectangle {
    in property <F4seUiRow> entry;

    min-height: root.entry.detail == "" ? 28px : 56px;
    background: root.entry.severity == "compatible" ? #1f3325 :
        root.entry.severity == "warning" ? #3a3118 :
        root.entry.severity == "incompatible" ? #3a2020 :
        #262626;
    border-color: root.entry.severity == "compatible" ? #3f7d4b :
        root.entry.severity == "warning" ? #8a6c21 :
        root.entry.severity == "incompatible" ? #8a3d3d :
        #383838;
    border-width: 1px;
    border-radius: 3px;

    VerticalLayout {
        padding: 5px;
        spacing: 2px;
        alignment: start;

        HorizontalLayout {
            spacing: 6px;
            alignment: start;

            SeverityCell {
                text: root.entry.dll;
                severity: root.entry.severity;
                important: true;
                width: 232px;
                font-size: 12px;
                horizontal-alignment: left;
            }

            SeverityCell {
                text: root.entry.og;
                severity: root.entry.severity;
                width: 54px;
                font-size: 15px;
                horizontal-alignment: center;
            }

            SeverityCell {
                text: root.entry.ng;
                severity: root.entry.severity;
                width: 54px;
                font-size: 15px;
                horizontal-alignment: center;
            }

            SeverityCell {
                text: root.entry.ae;
                severity: root.entry.severity;
                width: 54px;
                font-size: 15px;
                horizontal-alignment: center;
            }

            SeverityCell {
                text: root.entry.your_game;
                severity: root.entry.severity;
                width: 78px;
                font-size: 15px;
                horizontal-alignment: center;
            }
        }

        if root.entry.detail != "": Text {
            text: root.entry.detail;
            color: #c8c8c8;
            font-size: 11px;
            wrap: word-wrap;
        }
    }
}

component F4seStatusBanner inherits Rectangle {
    in property <string> message;
    in property <bool> error: false;

    height: 34px;
    background: root.error ? #4a2424 : #263447;
    border-color: root.error ? #d36b6b : #5e8fc2;
    border-width: 1px;
    border-radius: 4px;

    Text {
        text: root.message;
        color: root.error ? #ffd6d6 : #d9ebff;
        font-size: 13px;
        x: 8px;
        y: 8px;
        wrap: word-wrap;
    }
}

export component F4seTab inherits Rectangle {
    in-out property <string> f4se-status-text: "F4SE scan has not run yet.";
    in-out property <bool> f4se-busy: false;
    in-out property <string> f4se-loading-or-error-text: "";
    in-out property <string> f4se-unknown-game-detail: "";
    in-out property <[F4seUiRow]> f4se-rows;

    background: #202020;

    HorizontalLayout {
        padding: 20px;
        spacing: 12px;
        alignment: start;

        GroupBox {
            title: "DLL Compatibility";
            width: 540px;

            VerticalLayout {
                padding: 8px;
                spacing: 8px;
                alignment: start;

                HorizontalLayout {
                    spacing: 8px;
                    alignment: start;

                    Text {
                        text: "F4SE";
                        font-size: 18px;
                        font-weight: 600;
                        color: #f3f3f3;
                        vertical-alignment: center;
                    }

                    Text {
                        text: root.f4se-status-text;
                        color: root.f4se-busy ? #8ecbff : #d8d8d8;
                        font-size: 13px;
                        vertical-alignment: center;
                        wrap: word-wrap;
                    }
                }

                if root.f4se-loading-or-error-text != "": F4seStatusBanner {
                    message: root.f4se-loading-or-error-text;
                    error: !root.f4se-busy;
                }

                if root.f4se-unknown-game-detail != "": F4seStatusBanner {
                    message: root.f4se-unknown-game-detail;
                    error: false;
                }

                Rectangle {
                    height: 28px;
                    background: #303030;
                    border-color: #484848;
                    border-width: 1px;
                    border-radius: 3px;

                    HorizontalLayout {
                        padding-left: 5px;
                        padding-right: 5px;
                        spacing: 6px;
                        alignment: start;

                        F4seHeaderCell { text: "DLL"; cell-width: 232px; horizontal-alignment: left; }
                        F4seHeaderCell { text: "OG"; cell-width: 54px; }
                        F4seHeaderCell { text: "NG"; cell-width: 54px; }
                        F4seHeaderCell { text: "AE"; cell-width: 54px; }
                        F4seHeaderCell { text: "Your Game"; cell-width: 78px; }
                    }
                }

                ScrollView {
                    min-height: 390px;

                    VerticalLayout {
                        padding: 0px;
                        spacing: 4px;
                        alignment: start;

                        if root.f4se-rows.length == 0: Text {
                            text: root.f4se-busy ? "Scanning DLLs..." : "No F4SE DLL rows to display.";
                            color: #a8a8a8;
                            font-size: 12px;
                            wrap: word-wrap;
                        }

                        for row in root.f4se-rows: F4seRow {
                            entry: row;
                        }
                    }
                }
            }
        }

        GroupBox {
            title: "F4SE DLLs";
            width: 260px;

            ScrollView {
                Text {
                    text: "This checks all DLLs in\nData/F4SE/Plugins/ for\nversion-specific code to\ndetermine OG/NG support.\n\n✔ Version is supported\n\n❌ Version not supported\n\n❓ Not an F4SE DLL.\nMay still be loaded by\nother DLLs.\n\n⚠ Consult mod page to\nverify version support if\nyou see this icon.\nSome DLLs' version support\ncannot be reliably\ndetermined.";
                    color: #d8d8d8;
                    font-size: 12px;
                    wrap: word-wrap;
                }
            }
        }
    }
}

import { Button, GroupBox, ScrollView } from "std-widgets.slint";

component SafeErrorBanner inherits Rectangle {
    in property <string> message;

    height: 34px;
    background: #4a2424;
    border-color: #d36b6b;
    border-width: 1px;
    border-radius: 4px;

    Text {
        text: root.message;
        color: #ffd6d6;
        font-size: 13px;
        x: 8px;
        y: 8px;
        wrap: word-wrap;
    }
}

component ToolActionRow inherits Rectangle {
    in property <string> label;
    in property <string> action-id;
    in property <string> helper-text: "";
    in property <bool> button-enabled: true;

    callback action-requested(string);

    min-height: root.helper-text == "" ? 38px : 78px;

    HorizontalLayout {
        spacing: 8px;
        alignment: start;

        Button {
            text: root.label;
            enabled: root.button-enabled;
            width: 218px;
            clicked => {
                root.action-requested(root.action-id);
            }
        }

        if root.helper-text != "": Text {
            text: root.helper-text;
            color: #a8a8a8;
            font-size: 11px;
            wrap: word-wrap;
            vertical-alignment: center;
        }
    }
}

export component ToolsTab inherits Rectangle {
    in-out property <string> tools-last-action-error: "";
    in-out property <string> tools-disabled-utility-status: "Downgrade Manager is deferred until S09; Archive Patcher is deferred until S10.";

    callback tool-action-requested(string);

    background: #202020;

    ScrollView {
        HorizontalLayout {
            padding: 20px;
            spacing: 12px;
            alignment: start;

            GroupBox {
                title: "Toolkit Utilities";
                width: 282px;

                VerticalLayout {
                    padding: 8px;
                    spacing: 8px;
                    alignment: start;

                    if root.tools-last-action-error != "": SafeErrorBanner {
                        message: root.tools-last-action-error;
                    }

                    Text {
                        text: root.tools-disabled-utility-status;
                        color: #a8a8a8;
                        font-size: 12px;
                        wrap: word-wrap;
                    }

                    ToolActionRow {
                        label: "Downgrade Manager";
                        action-id: "tools.downgrade_manager";
                        button-enabled: false;
                        helper-text: "Deferred until S09 Downgrade Manager workflow is ported.";
                        action-requested(action_id) => {
                            root.tool-action-requested(action_id);
                        }
                    }

                    ToolActionRow {
                        label: "Archive Patcher";
                        action-id: "tools.archive_patcher";
                        button-enabled: false;
                        helper-text: "Deferred until S10 Archive Patcher workflow is ported.";
                        action-requested(action_id) => {
                            root.tool-action-requested(action_id);
                        }
                    }
                }
            }

            GroupBox {
                title: "Other CM Authors' Tools";
                width: 288px;

                VerticalLayout {
                    padding: 8px;
                    spacing: 8px;
                    alignment: start;

                    ToolActionRow {
                        label: "Bethini Pie";
                        action-id: "tools.bethini_pie";
                        helper-text: "Bethini Pie (Performance INI Editor) makes editing INI config files simple.\nDiscord channel: #bethini-doubleyou-etc";
                        action-requested(action_id) => {
                            root.tool-action-requested(action_id);
                        }
                    }

                    ToolActionRow {
                        label: "CLASSIC Crash Log Scanner";
                        action-id: "tools.classic_crash_log_scanner";
                        helper-text: "Scans Buffout crash logs for key indicators of crashes.\nYou can also post crash logs to the CM Discord for assistance.\nDiscord channel: #fo4-crash-logs";
                        action-requested(action_id) => {
                            root.tool-action-requested(action_id);
                        }
                    }

                    ToolActionRow {
                        label: "  Vault-Tec Enhanced\nFaceGen System (VEFS)";
                        action-id: "tools.vault_tec_enhanced_facegen_system";
                        helper-text: "Automates the process of generating FaceGen models and textures with xEdit/CK.\nDiscord channel: #bethini-doubleyou-etc";
                        action-requested(action_id) => {
                            root.tool-action-requested(action_id);
                        }
                    }

                    ToolActionRow {
                        label: "PJM's Precombine/Previs\n    Patching Scripts";
                        action-id: "tools.pjms_precombine_previs_patching_scripts";
                        helper-text: "Scripts to find precombine/previs (flickering/occlusion) errors in your mod list, and optionally generate a patch to fix those problems.";
                        action-requested(action_id) => {
                            root.tool-action-requested(action_id);
                        }
                    }

                    ToolActionRow {
                        label: "DDS Texture Scanner";
                        action-id: "tools.dds_texture_scanner";
                        helper-text: "Sniff out textures that might CTD your game. With BA2 support.\nDiscord channel: #nistonmakemod";
                        action-requested(action_id) => {
                            root.tool-action-requested(action_id);
                        }
                    }
                }
            }

            GroupBox {
                title: "Other Useful Tools";
                width: 288px;

                VerticalLayout {
                    padding: 8px;
                    spacing: 8px;
                    alignment: start;

                    ToolActionRow {
                        label: "xEdit / FO4Edit";
                        action-id: "tools.xedit_fo4edit";
                        helper-text: "Module editor and conflict detector for Bethesda games.\nFO4Edit/SSEEdit are xEdit, renamed to auto-set a game mode.";
                        action-requested(action_id) => {
                            root.tool-action-requested(action_id);
                        }
                    }

                    ToolActionRow {
                        label: "Creation Kit Platform\n   Extended (CKPE)";
                        action-id: "tools.creation_kit_platform_extended";
                        helper-text: "Various patches and bug fixes for the Creation Kit to make life easier.";
                        action-requested(action_id) => {
                            root.tool-action-requested(action_id);
                        }
                    }

                    ToolActionRow {
                        label: "Cathedral Assets\nOptimizer (CAO)";
                        action-id: "tools.cathedral_assets_optimizer";
                        helper-text: "An automation tool used to optimize BSAs, meshes, textures and animations.";
                        action-requested(action_id) => {
                            root.tool-action-requested(action_id);
                        }
                    }

                    ToolActionRow {
                        label: "BA2 Merging Automation\n     Tool (BMAT)";
                        action-id: "tools.ba2_merging_automation_tool";
                        helper-text: "Automated BA2 files repackaging and merging.";
                        action-requested(action_id) => {
                            root.tool-action-requested(action_id);
                        }
                    }

                    ToolActionRow {
                        label: "IceStorm's Texture Tools";
                        action-id: "tools.icestorms_texture_tools";
                        helper-text: "Converts textures from various formats into a Fallout 4 compatible format.";
                        action-requested(action_id) => {
                            root.tool-action-requested(action_id);
                        }
                    }

                    ToolActionRow {
                        label: "CapFrameX";
                        action-id: "tools.capframex";
                        helper-text: "Benchmarking tool - Record FPS, frametime, and sensors; analyse and plot the results.";
                        action-requested(action_id) => {
                            root.tool-action-requested(action_id);
                        }
                    }
                }
            }
        }
    }
}

//! Pure Scanner-tab domain contract.
//!
//! The reference Tkinter Scanner tab lives in `CMT/src/tabs/_scanner.py` and
//! shares problem records with the Overview tab through `ProblemInfo` and
//! `SimpleProblemInfo`. This module freezes the Scanner labels, settings
//! projection, grouping, detail rendering, read-only action descriptors, and
//! Overview handoff as inert Rust data so later services/controllers/UI code do
//! not need to duplicate reference strings or import Slint/platform APIs.

use std::{
    cmp::Ordering,
    path::{Path, PathBuf},
};

use crate::domain::{overview::OverviewProblem, settings::ScannerSettings};

/// Reference notebook tab title.
pub const SCANNER_TAB_TITLE: &str = "Scanner";
/// Reference side-pane labelframe title.
pub const SCAN_SETTINGS_GROUP_LABEL: &str = "Scan Settings";
/// Reference scan button label while idle.
pub const SCAN_BUTTON_LABEL: &str = "Scan Game";
/// Reference scan button label while a scan is active.
pub const SCANNING_BUTTON_LABEL: &str = "Scanning...";
/// Reference collapse tree button label.
pub const COLLAPSE_ALL_LABEL: &str = "Collapse All";
/// Reference expand tree button label.
pub const EXPAND_ALL_LABEL: &str = "Expand All";
/// Reference result-count suffix.
pub const RESULT_COUNT_SUFFIX: &str = "Results ~ Select an item for details";
/// Reference first progress text shown before scanner filesystem work starts.
pub const PROGRESS_REFRESHING_OVERVIEW_TEXT: &str = "Refreshing Overview...";
/// Reference progress text shown before building the MO2 mod-file index.
pub const PROGRESS_BUILDING_MOD_INDEX_TEXT: &str = "Building mod file index...";
/// Reference progress prefix while walking top-level Data folders.
pub const PROGRESS_SCANNING_PREFIX: &str = "Scanning...";
/// Reference initial progress value immediately after Overview handoff.
pub const PROGRESS_AFTER_OVERVIEW_PERCENT: f32 = 1.0;
/// Reference completion progress value.
pub const PROGRESS_COMPLETE_PERCENT: f32 = 100.0;
/// Reference delay between Tkinter queue polls in milliseconds.
pub const PROGRESS_CHECK_DELAY_MS: u64 = 100;
/// S07 intentionally renders scan settings from persisted state without editing them inline.
pub const SCANNER_SETTINGS_READ_ONLY_IN_S07: bool = true;
/// S07 read-only status for write-capable Auto-Fix behavior deferred to a later slice.
pub const AUTO_FIX_DEFERRED_STATUS: &str = "Auto-Fix is reserved for a later port phase.";

/// Reference race-subgraph threshold from `CMT/src/globals.py`.
